mapper.select:
SELECT COUNT(*)
FROM project_member
WHERE project_group_id = #{projectGroupId}

mapper.delete:
	DELETE FROM project_group
	WHERE project_group_id = #{projectGroupId}
  	AND project_id IN (
      	SELECT project_id
      	FROM project
      	WHERE owner_id = #{ownerId}
  	)

mapper.update:
	UPDATE project_member pm
	SET
    	pm.project_group_id = #{projectGroupId}
	WHERE pm.project_member_id = #{projectMemberId}
  	AND pm.project_group_id IS NULL
  	AND pm.project_id = (
      	SELECT pg.project_id
      	FROM project_group pg
      	JOIN project p
        	  ON pg.project_id = p.project_id
      	WHERE pg.project_group_id = #{projectGroupId}
    	    AND p.owner_id = #{ownerId}
	  )

	UPDATE project_member pm
	SET
    	pm.project_group_id = NULL
	WHERE pm.project_member_id = #{projectMemberId}
  	AND pm.project_group_id = #{projectGroupId}
  	AND pm.project_id = (
      	SELECT pg.project_id
      	FROM project_group pg
      	JOIN project p
        	  ON pg.project_id = p.project_id
      	WHERE pg.project_group_id = #{projectGroupId}
    	    AND p.owner_id = #{ownerId}
	  )
